else if (_error is not null)
{
    <div class="alert alert-danger">@_error</div>
}
else
{
    <!-- Summary stats bar -->
    <div class="stats-bar">
        <span class="stat-item">Total: <strong>@_allTasks.Count</strong></span>
        <span class="stat-item">To Do: <strong>@GetColumnTasks("To Do").Count</strong></span>
        <span class="stat-item">In Progress: <strong>@GetColumnTasks("In Progress").Count</strong></span>
        <span class="stat-item">Done: <strong>@GetColumnTasks("Done").Count</strong></span>
        <span class="stat-item stat-overdue">Overdue: <strong>@_allTasks.Count(t => t.DueDate.Date < DateTime.Today)</strong></span>
    </div>

    <!-- Search bar -->
    <div class="search-bar">
        <input type="text" class="form-control" placeholder="Search tasks by title…"
               @bind="_searchText" @bind:event="oninput" />
    </div>

    <!-- Kanban columns -->
    <div class="kanban-container">
        @foreach (var column in _columns)
        {
            var tasks = GetFilteredColumnTasks(column);
            <div class="kanban-column">
                <div class="column-header">
                    <h3>@column</h3>
                    <span class="badge bg-secondary">@tasks.Count</span>
                </div>

                <div class="column-body">
                    @foreach (var task in tasks)
                    {
                        <div class="task-card">
                            <div class="task-title">@task.Title</div>
                            <div class="task-assignee">@task.Assignee</div>
                            <span class="priority-badge priority-@task.Priority.ToLowerInvariant()">@task.Priority</span>
                            <div class="task-due">@task.DueDate.ToString("MMM dd")</div>
                            <div class="task-actions">
                                @if (GetColumnIndex(column) > 0)
                                {
                                    <button class="btn btn-sm btn-outline-secondary"
                                            @onclick="() => MoveTaskAsync(task.Id, _columns[GetColumnIndex(column) - 1])">
                                        ← Move Left
                                    </button>
                                }
                                @if (GetColumnIndex(column) < _columns.Length - 1)
                                {
                                    <button class="btn btn-sm btn-outline-secondary"
                                            @onclick="() => MoveTaskAsync(task.Id, _columns[GetColumnIndex(column) + 1])">
                                        Move Right →
                                    </button>
                                }
                            </div>
                        </div>
                    }
                </div>

                @if (_addingToColumn == column)
                {
                    <div class="add-task-form">
                        <input type="text" class="form-control mb-1" placeholder="Title"
                               @bind="_newTitle" />
                        <input type="text" class="form-control mb-1" placeholder="Assignee"
                               @bind="_newAssignee" />
                        <select class="form-select mb-1" @bind="_newPriority">
                            <option value="High">High</option>
                            <option value="Medium">Medium</option>
                            <option value="Low">Low</option>
                        </select>
                        <input type="date" class="form-control mb-1"
                               @bind="_newDueDate" />
                        <div class="d-flex gap-1">
                            <button class="btn btn-sm btn-primary" @onclick="SaveNewTaskAsync">Save</button>
                            <button class="btn btn-sm btn-secondary" @onclick="CancelAdd">Cancel</button>
                        </div>
                    </div>
                }
                else
                {
                    <button class="btn btn-sm btn-outline-primary add-task-btn"
                            @onclick="() => StartAdd(column)">
                        + Add Task
                    </button>
                }
            </div>
        }
    </div>
}

@code {
    private readonly string[] _columns = ["To Do", "In Progress", "Done"];

    private List<TaskItem> _allTasks = new();
    private bool _loading = true;
    private string? _error;
    private string _searchText = string.Empty;

    // Add-task form state
    private string? _addingToColumn;
    private string _newTitle = string.Empty;
    private string _newAssignee = string.Empty;
    private string _newPriority = "Medium";
    private DateTime _newDueDate = DateTime.Today.AddDays(7);

    protected override async Task OnInitializedAsync()
    {
        try
        {
            _allTasks = await TaskService.GetAllTasksAsync();
        }
        catch (Exception ex)
        {
            _error = $"Failed to load tasks: {ex.Message}";
        }
        finally
        {
            _loading = false;
        }
    }

    private List<TaskItem> GetColumnTasks(string status) =>
        _allTasks.Where(t => t.Status == status).ToList();

    private List<TaskItem> GetFilteredColumnTasks(string status)
    {
        var tasks = GetColumnTasks(status);
        if (!string.IsNullOrWhiteSpace(_searchText))
        {
            tasks = tasks.Where(t => t.Title.Contains(_searchText, StringComparison.OrdinalIgnoreCase)).ToList();
        }
        return tasks;
    }

    private int GetColumnIndex(string column) => Array.IndexOf(_columns, column);

    private async Task MoveTaskAsync(int taskId, string newStatus)
    {
        try
        {
            await TaskService.UpdateTaskStatusAsync(taskId, newStatus);
            var task = _allTasks.First(t => t.Id == taskId);
            _allTasks[_allTasks.IndexOf(task)] = task with { Status = newStatus };
        }
        catch (Exception ex)
        {
            _error = $"Failed to move task: {ex.Message}";
        }
    }

    private void StartAdd(string column)
    {
        _addingToColumn = column;
        _newTitle = string.Empty;
        _newAssignee = string.Empty;
        _newPriority = "Medium";
        _newDueDate = DateTime.Today.AddDays(7);
    }

    private void CancelAdd() => _addingToColumn = null;

    private async Task SaveNewTaskAsync()
    {
        if (string.IsNullOrWhiteSpace(_newTitle) || _addingToColumn is null) return;

        try
        {
            var created = await TaskService.CreateTaskAsync(_newTitle, _newAssignee, _newPriority, _newDueDate);
            // CreateTaskAsync returns the task with its default status; update to the target column if needed
            if (created.Status != _addingToColumn)
            {
                await TaskService.UpdateTaskStatusAsync(created.Id, _addingToColumn);
                created = created with { Status = _addingToColumn };
            }
            _allTasks.Add(created);
            _addingToColumn = null;
        }
        catch (Exception ex)
        {
            _error = $"Failed to create task: {ex.Message}";
        }
    }
}

