arguments.file_text:
.stats-bar {
    display: flex;
    gap: 1.5rem;
    padding: 0.75rem 1rem;
    background: #f8f9fa;
    border-radius: 0.5rem;
    margin-bottom: 1rem;
    flex-wrap: wrap;
}

.stat-item {
    font-size: 0.95rem;
}

.stat-overdue strong {
    color: #dc3545;
}

.search-bar {
    margin-bottom: 1rem;
    max-width: 400px;
}

.kanban-container {
    display: flex;
    gap: 1rem;
    align-items: flex-start;
}

.kanban-column {
    flex: 1;
    min-width: 250px;
    background: #f0f0f0;
    border-radius: 0.5rem;
    padding: 0.75rem;
    display: flex;
    flex-direction: column;
}

.column-header {
    display: flex;
    justify-content: space-between;
    align-items: center;
    margin-bottom: 0.75rem;
}

.column-header h3 {
    margin: 0;
    font-size: 1.1rem;
}

.column-body {
    display: flex;
    flex-direction: column;
    gap: 0.5rem;
    min-height: 60px;
}

.task-card {
    background: #fff;
    border: 1px solid #dee2e6;
    border-radius: 0.375rem;
    padding: 0.75rem;
}

.task-title {
    font-weight: 600;
    margin-bottom: 0.25rem;
}

.task-assignee {
    font-size: 0.85rem;
    color: #6c757d;
    margin-bottom: 0.25rem;
}

.task-due {
    font-size: 0.85rem;
    color: #495057;
    margin-top: 0.25rem;
}

.priority-badge {
    display: inline-block;
    padding: 0.15rem 0.5rem;
    border-radius: 0.25rem;
    font-size: 0.75rem;
    font-weight: 600;
    color: #fff;
}

.priority-high {
    background-color: #dc3545;
}

.priority-medium {
    background-color: #ffc107;
    color: #212529;
}

.priority-low {
    background-color: #198754;
}

.task-actions {
    display: flex;
    gap: 0.35rem;
    margin-top: 0.5rem;
}

.add-task-form {
    margin-top: 0.75rem;
    padding: 0.75rem;
    background: #fff;
    border: 1px dashed #adb5bd;
    border-radius: 0.375rem;
